function setup() { canvas(); }
function draw() {
  background(255);
  let vecStyle = { color: color(200, 0, 0) };
  let v1 = pvector(100, 300, 300, 200);
  let v2 = pvector(100, 300, 200, 100);
  v1.draw(vecStyle);
