  let v1copy = v1.placeAt(200, 100);
  v1copy.draw({ color: color(100, 100, 100) });
}

let stepper;
function setup() { canvas(); stepper = phaseStepper(2); }
function draw() {
  background(255);
  let v = pvector(100, 300, 300, 150);
  let t1 = stepper.phaseT(1);
  if (t1 > 0) v.drawAnimated(t1, { color: color(200, 0, 0) });
  let t2 = stepper.phaseT(2);
  if (t2 > 0) v.drawPlaceAt(200, 100, t2, { color: color(100, 100, 100) });
  stepper.draw();
}
function mousePressed() { stepper.handleClick(); }

